import React from "react"
import moment from "moment";
import { properties } from '../../properties/properties.js'
var xlsx = require("xlsx");


class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedFile: null, totalBlock: 0, people: []
        };
    }

    handleselectedFile = event => {
        //console.log(event.target.files[0])
        this.setState({
          selectedFile: event.target.files[0]
        })
      }

    handleAddBlock = event => {

    }



    handleUpload = (e) => {

        this.setState({screen: 1})

        e.preventDefault();

        var reader = new FileReader();
        const scope = this;
        reader.onload = function (e) {


            function findV(cellValue) {
                var value_v = "";
                if (typeof cellValue !== 'undefined')
                    value_v = cellValue.v
                else
                    value_v = ""
                return value_v;
            }

            function findW(cellValue) {
                var value_w = "";
                if (typeof cellValue !== 'undefined') {
                    value_w = moment(cellValue.w,'M/D/YY').format('MM/DD/YYYY')

                } else {
                    value_w = ""
                }
                return value_w;
            }


            var data = e.target.result;
            let wb = xlsx.read(data, {type: 'binary'});
            //const wsname = readedData.SheetNames[0];
            //const ws = readedData.Sheets[wsname];
            var people = []

            var ws = wb.Sheets[wb.SheetNames[0]];

            var totalBlock = findV(ws[xlsx.utils.encode_cell({r: 0, c: 1})])
            scope.setState({totalBlock: totalBlock})
            console.log(totalBlock)
            var range = xlsx.utils.decode_range(ws['!ref']);
            for (let rowNum = 3; rowNum <= range.e.r; rowNum++) {
                people.push({name: findV(ws[xlsx.utils.encode_cell({r: rowNum, c: 0})]),clinic: findV(ws[xlsx.utils.encode_cell({r: rowNum, c: 1})])})
            }

            scope.setState({people: people})
            scope.setState({screen: 5})
        };

        reader.readAsBinaryString(this.state.selectedFile)



      }



    componentDidMount() {




      }


      findOnCall = (rec, rec2) => {

        var findAmionData = this.state.amionData.filter(amionRed => amionRed.name == rec2.name && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") >= moment(rec.startDate, "YYYY-MM-DD").add(-1, "M").format("YYYY-MM-DD") && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") <= rec.startDate)

        findAmionData.sort(function(a,b) {
            return new Date(b.date) - new Date(a.date)
        })

        var onCallString = ""

        findAmionData.map(aDRec => {
            var before = rec2.before.split("|").map(item=>item.trim())

            before.map(bRec => {
                //console.log(bRec)
                if (bRec.toLowerCase() == "sf5r") {
                    if (aDRec.service.toLowerCase().includes("sf5r int long call") && onCallString == "") {
                        onCallString = moment(aDRec.date, "M-D-YY").format("MM/DD") + " on call"
                    }
                } else {
                    if (aDRec.service.toLowerCase().includes(bRec.toLowerCase()) && aDRec.service.toLowerCase() != bRec.toLowerCase() && onCallString == "") {
                        //console.log(findAmionData)
                        if (!aDRec.service.toLowerCase().includes("sfnfv x-cover")) {
                            onCallString = moment(aDRec.date, "M-D-YY").format("MM/DD") + " on call"
                        }
                    }
                }
            })

        })

        return onCallString

      }


          render() {


            var header = ""

            var content = []
            //var items = []


            //content.push(<div>Add Block <input type="text" name="blockLabel"></input><button onClick={this.handleUpload}>Add</button></div>)






            content.push(<div >
            <input type="hidden" name="todayDate" value={this.state.todayDay} />
            <input type="file" name="blockFile" id="blockFile" onChange={this.handleselectedFile} />
            <button onClick={this.handleUpload}>Upload</button>
          </div>)


                if (this.state.screen == 1) {
                    content.push(<div style={{marginTop: "10px"}}>Loading ...</div>)
                }



                if (this.state.screen == 5) {

                   var tableTd = []
                   var tableTr = []

                    var i = 1
                    tableTd.push(<td style={{border: "solid", borderWidth: "1px"}}>Name</td>)
                    while (i <= this.state.totalBlock) {
                        tableTd.push(<td style={{border: "solid", borderWidth: "1px"}}>block {i}</td>)
                        i += 1
                    }

                   tableTr.push(<tr>{tableTd}</tr>)



                   this.state.people.map(rec => {
                    tableTd = []

                    tableTd.push(<td style={{border: "solid", borderWidth: "1px"}}>{rec.name}</td>)


                    var i = 1
                    while (i <= this.state.totalBlock) {
                        if (rec.clinic === i) {
                            tableTd.push(<td style={{border: "solid", borderWidth: "1px"}}>Clinic</td>)
                        } else {
                            tableTd.push(<td style={{border: "solid", borderWidth: "1px"}}></td>)
                        }

                        i += 1
                    }


                    tableTr.push(<tr>{tableTd}</tr>)
                   })




                    content.push(<div style={{marginTop: "10px"}}><table style={{border: "solid", borderWidth: "1px"}}>{tableTr}</table></div>)

                }



                if (this.state.screen == 2) {


                    //console.log(this.state.amionData)



                    var R1GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R1" && filterRec.rotation.includes("UCW")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UCW"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UCW"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UCW"))}});
                    var R2GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => (filterRec.sheetName == "R2" || filterRec.sheetName == "R3") && filterRec.rotation.includes("UCW")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UCW"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UCW"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UCW"))}});
                    //var R3GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R3" && filterRec.rotation == "UCW").map(groups => groups.date))).map(group => {return {date: group, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R3" && Record.rotation == "UCW")}});

                    var R1GroupUCCard = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R1" && filterRec.rotation.includes("UC Card")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UC Card"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UC Card"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UC Card"))}});
                    var R2GroupUCCard = Array.from(new Set(this.state.results.filter(filterRec => (filterRec.sheetName == "R2" || filterRec.sheetName == "R3") && filterRec.rotation.includes("UC Card")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UC Card"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UC Card"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UC Card"))}});
                    //var R3GroupUCCard = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R3" && filterRec.rotation == "UC Card").map(groups => groups.date))).map(group => {return {date: group, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R3" && Record.rotation == "UC Card")}});


                    //console.log(R1GroupUCW)

                    content.push(<div><h2>UCW</h2><hr></hr></div>)
                    content.push(<div><h3>Residents</h3><hr></hr></div>)



                    R1GroupUCW.map(rec => {
                        content.push(<div><h4>{rec.date}</h4></div>)
                        //content.push(<div><h4>{rec.startDate} - {rec.endDate}</h4></div>)
                        var tr = []

                        var teamChoice = ["A","B","C","D","E","F","G","H"]
                        var teamChoice2 = ["A","B","C","D","E","F","G","H"]

                        rec.data.map(rec2 => {

                            var teamString = ""
                            if (teamChoice.length > 0) {
                                var arrayRandomNum = Math.floor(Math.random()*teamChoice.length)
                                teamString = "Team " + teamChoice[arrayRandomNum]
                                teamChoice.splice(arrayRandomNum, 1)
                                //console.log(teamChoice)
                            } else {
                                if (teamChoice2.length > 0) {
                                    var arrayRandomNum = Math.floor(Math.random()*teamChoice2.length)
                                    teamString = "Team " + teamChoice2[arrayRandomNum]
                                    teamChoice2.splice(arrayRandomNum, 1)
                                    //console.log(teamChoice2)
                                }
                            }


                            /*
                            //console.log(rec.startDate + " " + rec.endDate)
                            //console.log(this.state.amionData)
                            var findAmionData = this.state.amionData.filter(amionRed => amionRed.name == rec2.name && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") >= moment(rec.startDate, "YYYY-MM-DD").add(-1, "M").format("YYYY-MM-DD") && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") <= rec.startDate)
                            //var findAmionData = this.state.amionData.filter(amionRed => amionRed.name == rec2.name)
                            findAmionData.sort(function(a,b) {
                                //var x = a.formatDate.toLowerCase();
                                //var y = b.formatDate.toLowerCase();
                                //return x < y ? -1 : x > y ? 1: 0;
                                return new Date(b.date) - new Date(a.date)
                            })

                            var onCallString = ""


